import pytest, requests

def test_update_patient_stale_version_returns_409(clinician_token, create_patient, base_url):
    patient_id, v1_id = create_patient
    auth = {"Authorization": f"Bearer {clinician_token}"}
    ct = "application/fhir+json"

    def _put(version_id, family):
        return requests.put(
            f"{base_url}/Patient/{patient_id}",
            json={
                "resourceType": "Patient",
                "id": patient_id,
                "meta": {"versionId": version_id},
                "name": [{"family": family}],
            },
            headers={**auth, "Content-Type": ct, "If-Match": f'W/"{version_id}"'},
        )

    advance = _put(v1_id, "FirstUpdate")
    assert advance.status_code == 200, advance.text

    stale = _put(v1_id, "StaleUpdate")
    assert stale.status_code == 409, stale.text
    outcome = stale.json()
    assert outcome.get("resourceType") == "OperationOutcome"
